// MARK: - Models

enum APIError: Error {
    case network, decoding, unauthorized, unknown
}

struct StockQuote: Identifiable, Decodable {
    let id: String           // Ticker
    let price: Double
    let change: Double
    let timestamp: Date
}

struct Order: Encodable {
    enum Side: String, Encodable { case buy, sell }
    let symbol: String
    let quantity: Int
    let side: Side
    let price: Double?
}

struct OrderResponse: Decodable {
    let orderId: String
    let status: String
    let filledQuantity: Int
    let avgPrice: Double?
}

struct PortfolioPosition: Identifiable, Decodable {
    let id: String           // Ticker
    let quantity: Int
    let avgPrice: Double
    var marketPrice: Double?
    
    var marketValue: Double {
        (marketPrice ?? 0) * Double(quantity)
    }
}

// MARK: - Secure Token Storage

final class KeychainTokenStore {
    private let service = "com.yourcompany.tradingapp"
    private let account = "authToken"
    
    func save(token: String) {
        let data = Data(token.utf8)
        let query: [String: Any] = [
            kSecClass as String       : kSecClassGenericPassword,
            kSecAttrService as String : service,
            kSecAttrAccount as String : account,
            kSecValueData as String   : data,
            kSecAttrAccessible as String: kSecAttrAccessibleAfterFirstUnlock
        ]
        SecItemDelete(query as CFDictionary)
        SecItemAdd(query as CFDictionary, nil)
    }
    
    func retrieve() -> String? {
        let query: [String: Any] = [
            kSecClass as String       : kSecClassGenericPassword,
            kSecAttrService as String : service,
            kSecAttrAccount as String : account,
            kSecReturnData as String  : true,
            kSecMatchLimit as String  : kSecMatchLimitOne
        ]
        var item: CFTypeRef?
        guard SecItemCopyMatching(query as CFDictionary, &item) == errSecSuccess,
              let data = item as? Data,
              let token = String(data: data, encoding: .utf8) else { return nil }
        return token
    }
}

// MARK: - API Layer

final class APIService {
    static let shared = APIService()
    private init() {}
    
    private let baseURL = URL(string: "https://api.yourbroker.com")!
    private let session: URLSession = {
        let cfg = URLSessionConfiguration.default
        cfg.timeoutIntervalForRequest = 10
        cfg.timeoutIntervalForResource = 30
        return URLSession(configuration: cfg)
    }()
    
    private var cancellables = Set<AnyCancellable>()
    private var webSocketTask: URLSessionWebSocketTask?
    
    private var tokenStore = KeychainTokenStore()
    
    private var authToken: String? {
        tokenStore.retrieve()
    }
    
    func authenticate(username: String, password: String) -> AnyPublisher<Void, APIError> {
        var req = URLRequest(url: baseURL.appendingPathComponent("/auth/login"))
        req.httpMethod = "POST"
        let body = ["username": username, "password": password]
        req.httpBody = try? JSONEncoder().encode(body)
        req.addValue("application/json", forHTTPHeaderField: "Content-Type")
        
        return session.dataTaskPublisher(for: req)
            .tryMap { output in
                guard let resp = output.response as? HTTPURLResponse else { throw APIError.unknown }
                guard resp.statusCode == 200 else { throw APIError.unauthorized }
                return output.data
            }
            .decode(type: [String:String].self, decoder: JSONDecoder())
            .tryMap { dict in
                guard let token = dict["token"] else { throw APIError.unauthorized }
                self.tokenStore.save(token: token)
                return ()
            }
            .mapError { _ in APIError.unauthorized }
            .eraseToAnyPublisher()
    }
    
    private func request(path: String,
                         method: String = "GET",
                         body: Data? = nil) -> URLRequest {
        var req = URLRequest(url: baseURL.appendingPathComponent(path))
        req.httpMethod = method
        if let token = authToken {
            req.addValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        if let body = body {
            req.httpBody = body
            req.addValue("application/json", forHTTPHeaderField: "Content-Type")
        }
        return req
    }
    
    func fetchQuote(symbol: String) -> AnyPublisher<StockQuote, APIError> {
        session.dataTaskPublisher(for: request(path: "/market/quote/\(symbol)"))
            .mapError { _ in APIError.network }
            .tryMap { output in
                guard let resp = output.response as? HTTPURLResponse,
                      200..<300 ~= resp.statusCode else { throw APIError.network }
                return output.data
            }
            .decode(type: StockQuote.self, decoder: JSONDecoder())
            .mapError { _ in APIError.decoding }
            .eraseToAnyPublisher()
    }
    
    func placeOrder(_ order: Order) -> AnyPublisher<OrderResponse, APIError> {
        let body = try? JSONEncoder().encode(order)
        return session.dataTaskPublisher(for: request(path: "/orders", method: "POST", body: body))
            .mapError { _ in APIError.network }
            .tryMap { output in
                guard let resp = output.response as? HTTPURLResponse,
                      200..<300 ~= resp.statusCode else { throw APIError.network }
                return output.data
            }
            .decode(type: OrderResponse.self, decoder: JSONDecoder())
            .mapError { _ in APIError.decoding }
            .eraseToAnyPublisher()
    }
    
    func fetchPortfolio() -> AnyPublisher<[PortfolioPosition], APIError> {
        session.dataTaskPublisher(for: request(path: "/portfolio"))
            .mapError { _ in APIError.network }
            .tryMap { output in
                guard let resp = output.response as? HTTPURLResponse,
                      200..<300 ~= resp.statusCode else { throw APIError.network }
                return output.data
            }
            .decode(type: [PortfolioPosition].self, decoder: JSONDecoder())
            .mapError { _ in APIError.decoding }
            .eraseToAnyPublisher()
    }
    
    func connectLiveQuotes(symbols: [String],
                           receive: @escaping (StockQuote) -> Void) {
        webSocketTask?.cancel(with: .goingAway, reason: nil)
        guard let url = URL(string: "wss://stream.yourbroker.com/quotes?symbols=\(symbols.joined(separator: ","))") else { return }
        var req = URLRequest(url: url)
        if let token = authToken {
            req.addValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        webSocketTask = session.webSocketTask(with: req)
        webSocketTask?.resume()
        listen(receive: receive)
    }
    
    private func listen(receive: @escaping (StockQuote) -> Void) {
        webSocketTask?.receive { [weak self] result in
            switch result {
            case .failure:
                break
            case .success(.string(let text)):
                if let data = text.data(using: .utf8),
                   let quote = try? JSONDecoder().decode(StockQuote.self, from: data) {
                    DispatchQueue.main.async { receive(quote) }
                }
            default: break
            }
            self?.listen(receive: receive)
        }
    }
}

// MARK: - Portfolio Manager

final class PortfolioManager: ObservableObject {
    @Published private(set) var positions: [PortfolioPosition] = []
    @Published var cashBalance: Double = 0
    
    private var cancellables = Set<AnyCancellable>()
    
    func load() {
        APIService.shared.fetchPortfolio()
            .receive(on: DispatchQueue.main)
            .sink(receiveCompletion: { _ in },
                  receiveValue: { [weak self] positions in
                    self?.positions = positions
            })
            .store(in: &cancellables)
    }
    
    func updateQuote(_ quote: StockQuote) {
        guard let index = positions.firstIndex(where: { $0.id == quote.id }) else { return }
        positions[index].marketPrice = quote.price
    }
    
    func totalMarketValue() -> Double {
        positions.reduce(0) { $0 + $1.marketValue }
    }
}

// MARK: - Trading ViewModel

final class TradingViewModel: ObservableObject {
    enum TradeState { case ready, sending, success(String), failure(String) }
    
    @Published var symbol = ""
    @Published var quantity = ""
    @Published var side: Order.Side = .buy
    @Published private(set) var state: TradeState = .ready
    
    private var cancellables = Set<AnyCancellable>()
    
    func submit() {
        guard let qty = Int(quantity), !symbol.isEmpty, qty > 0 else {
            state = .failure("Invalid input")
            return
        }
        state = .sending
        let order = Order(symbol: symbol.uppercased(), quantity: qty, side: side, price: nil)
        APIService.shared.placeOrder(order)
            .receive(on: DispatchQueue.main)
            .sink(receiveCompletion: { [weak self] completion in
                if case .failure(_) = completion {
                    self?.state = .failure("Order failed")
                }
            }, receiveValue: { [weak self] response in
                self?.state = .success(response.status)
            })
            .store(in: &cancellables)
    }
}

