struct TradeView: View {
    @StateObject private var vm = TradingViewModel()
    
    var body: some View {
        NavigationView {
            Form {
                Section(header: Text("Symbol")) {
                    TextField("e.g. AAPL", text: $vm.symbol)
                        .autocapitalization(.allCharacters)
                }
                Section(header: Text("Quantity")) {
                    TextField("Shares", text: $vm.quantity)
                        .keyboardType(.numberPad)
                }
                Section(header: Text("Side")) {
                    Picker("Side", selection: $vm.side) {
                        Text("Buy").tag(Order.Side.buy)
                        Text("Sell").tag(Order.Side.sell)
                    }
                    .pickerStyle(SegmentedPickerStyle())
                }
                Section {
                    Button(action: {
                        vm.submit()
                    }) {
                        HStack {
                            Spacer()
                            if case .sending = vm.state {
                                ProgressView()
                            } else {
                                Text("Submit Order")
                            }
                            Spacer()
                        }
                    }
                    .disabled(vm.state == .sending)
                }
            }
            .navigationTitle("Trade")
            .alert(isPresented: Binding<Bool>(
                get: {
                    if case .success(_) = vm.state { return true }
                    if case .failure(_) = vm.state { return true }
                    return false
                },
                set: { _ in vm.state = .ready })
            ) {
                switch vm.state {
                case .success(let msg):
                    return Alert(title: Text("Success"),
                                 message: Text(msg),
                                 dismissButton: .default(Text("OK")))
                case .failure(let err):
                    return Alert(title: Text("Error"),
                                 message: Text(err),
                                 dismissButton: .default(Text("OK")))
                default:
                    return Alert(title: Text(""), message: Text(""), dismissButton: .cancel())
                }
            }
        }
    }
}

